cssRules:
@media screen and (min-width: 768px) {
  .md\:text-left .split-words { justify-content: flex-start; }
  .md\:text-center .split-words { justify-content: center; }
  .md\:text-right .split-words { justify-content: flex-end; }
}

@media screen and (min-width: 1024px) {
  .lg\:text-left .split-words { justify-content: flex-start; }
  .lg\:text-center .split-words { justify-content: center; }
  .lg\:text-right .split-words { justify-content: flex-end; }
}

@media screen and (min-width: 768px) {
  .reveal-testimonials { padding-block-start: clamp(var(--sp-8),2.526vw,var(--sp-12)); width: calc(clamp(340px,30vw,480px) * 2 - var(--sp-20)); }
  .reveal-testimonials .testimonial { width: clamp(340px, 30vw, 480px); }
  .testimonials-title { position: sticky; inset-block-start: 50%; transform: translateY(-50%); }
  .testimonials-title .split-words ~ .split-words { transform: translateY(100%); }
}
